import React, { useState, useEffect, useRef } from 'react';
import { slotAPI } from '../services/api';
import io from 'socket.io-client';

const ClockIcon = () => (
  <svg className="slot-meta-icon" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
    <path strokeLinecap="round" strokeLinejoin="round" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
  </svg>
);

const HourglassIcon = () => (
  <svg className="slot-meta-icon" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
    <path strokeLinecap="round" strokeLinejoin="round" d="M12 6v6m0 0v6m0-6h6m-6 0H6" />
  </svg>
);

const BookIcon = () => (
  <svg className="slot-meta-icon" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
    <path strokeLinecap="round" strokeLinejoin="round" d="M12 14l9-5-9-5-9 5 9 5z" />
    <path strokeLinecap="round" strokeLinejoin="round" d="M12 14l6.16-3.422a12.083 12.083 0 01.665 6.479A11.952 11.952 0 0012 20.055a11.952 11.952 0 00-6.824-2.998 12.078 12.078 0 01.665-6.479L12 14z" />
    <path strokeLinecap="round" strokeLinejoin="round" d="M12 14l9-5-9-5-9 5 9 5zm0 0l6.16-3.422a12.083 12.083 0 01.665 6.479A11.952 11.952 0 0012 20.055a11.952 11.952 0 00-6.824-2.998 12.078 12.078 0 01.665-6.479L12 14zm-4 6v-7.5l4-2.222" />
  </svg>
);

const SlotBookingPage = () => {
  const [slots, setSlots] = useState([]);
  const [bookedSlots, setBookedSlots] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [view, setView] = useState('available');
  const [successMessage, setSuccessMessage] = useState('');
  const socketRef = useRef(null);

  useEffect(() => {
    fetchSlots();
  }, []);

  useEffect(() => {
    socketRef.current = io('http://localhost:5000', {
      auth: {
        token: sessionStorage.getItem('token') || localStorage.getItem('token'),
      },
    });

    socketRef.current.on('slot_updated', () => {
      fetchSlots();
    });

    return () => {
      socketRef.current.off('slot_updated');
      socketRef.current.disconnect();
    };
  }, []);

  const fetchSlots = async () => {
    setLoading(true);
    setError('');
    try {
      const [availableRes, bookedRes] = await Promise.all([
        slotAPI.getAvailableSlots(),
        slotAPI.getMySlots(),
      ]);
      setSlots(availableRes.data.slots || []);
      setBookedSlots(bookedRes.data.slots || []);
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to fetch slots');
    } finally {
      setLoading(false);
    }
  };

  const handleBookSlot = async (slotId) => {
    try {
      await slotAPI.bookSlot({ slotId });
      setSuccessMessage('Session booked successfully.');
      setTimeout(() => setSuccessMessage(''), 3000);
      fetchSlots();
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to book slot');
    }
  };

  const handleCancelBooking = async (slotId) => {
    try {
      await slotAPI.cancelBooking(slotId);
      setSuccessMessage('Booking cancelled successfully.');
      setTimeout(() => setSuccessMessage(''), 3000);
      fetchSlots();
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to cancel booking');
    }
  };

  const formatDateTime = (date, time) => {
    try {
      return `${new Date(date).toLocaleDateString()} at ${time}`;
    } catch {
      return `${date} at ${time}`;
    }
  };

  const isSlotFinished = (dateStr, timeStr, durationMinutes) => {
    if (!dateStr || !timeStr) return false;
    try {
      const slotStart = new Date(`${dateStr.split('T')[0]}T${timeStr}`);
      if (isNaN(slotStart.getTime())) return false;

      const slotEnd = new Date(slotStart.getTime() + (durationMinutes || 30) * 60000);
      return new Date() > slotEnd;
    } catch {
      return false;
    }
  };

  const currentSlots = view === 'available' ? slots : bookedSlots;

  return (
    <div className="container-fluid py-4 min-vh-100">
      <div className="container">

        <div className="premium-hero-card p-4 p-md-5 mb-5 text-center text-md-start">
          <span className="premium-hero-kicker">Interactive Sessions</span>
          <h1 className="premium-hero-title">Slot Booking</h1>
          <p className="premium-hero-copy">
            Reserve available sessions with staff members and keep track of your confirmed bookings below.
          </p>
          <div className="premium-hero-grid mt-4">
            <div className="premium-hero-stat">
              <div className="premium-hero-stat-label">Available</div>
              <div className="premium-hero-stat-value">{slots.length}</div>
            </div>
            <div className="premium-hero-stat">
              <div className="premium-hero-stat-label">Booked</div>
              <div className="premium-hero-stat-value">{bookedSlots.length}</div>
            </div>
          </div>
        </div>

        {error && (
          <div className="alert alert-danger alert-dismissible fade show" role="alert">
            {error}
            <button type="button" className="btn-close" onClick={() => setError('')}></button>
          </div>
        )}

        {successMessage && (
          <div className="alert alert-success alert-dismissible fade show" role="alert">
            {successMessage}
            <button
              type="button"
              className="btn-close"
              onClick={() => setSuccessMessage('')}
            ></button>
          </div>
        )}

        <div className="mb-5 text-center">
          <div className="premium-segment-control">
            <div className="premium-segment-highlight" style={{ transform: `translateX(${view === 'available' ? '0' : '100%'})` }}></div>
            <button
              type="button"
              className={`premium-segment-btn ${view === 'available' ? 'active' : ''}`}
              onClick={() => setView('available')}
            >
              Available Slots
            </button>
            <button
              type="button"
              className={`premium-segment-btn ${view === 'booked' ? 'active' : ''}`}
              onClick={() => setView('booked')}
            >
              My Bookings
            </button>
          </div>
        </div>

        {loading ? (
          <div className="text-center py-5">
            <div className="spinner-border text-primary" role="status">
              <span className="visually-hidden">Loading...</span>
            </div>
          </div>
        ) : currentSlots.length === 0 ? (
          <div className="premium-hero-card text-center p-5 mt-4" style={{ background: 'rgba(255, 255, 255, 0.02)' }}>
            <div className="mb-4 text-muted opacity-50">
              <svg width="64" height="64" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1" strokeLinecap="round" strokeLinejoin="round">
                <circle cx="12" cy="12" r="10"></circle><polyline points="12 6 12 12 16 14"></polyline>
              </svg>
            </div>
            <h4 className="fw-bold mb-3">No Sessions Found</h4>
            <div className="text-muted" style={{ maxWidth: '400px', margin: '0 auto' }}>
              {view === 'available'
                ? 'There are currently no open slots available. Check back soon when staff members update their schedules.'
                : 'Your upcoming schedule is clear. You have not booked any sessions yet. Browse available slots to get started.'}
            </div>
          </div>
        ) : (
          <div className="row g-5">
            {currentSlots.map((slot) => (
              <div key={slot._id} className="col-md-6 col-lg-4">
                <div className="premium-slot-card p-4 d-flex flex-column h-100">
                  <div className="d-flex justify-content-between align-items-start mb-4">
                    <div>
                      <div className="portal-stat-label text-muted mb-1 text-uppercase" style={{ fontSize: '0.75rem', letterSpacing: '1px' }}>
                        Session
                      </div>
                      <h5 className="fw-bold mb-0 text-white" style={{ fontSize: '1.25rem' }}>{slot.staffId?.name || 'Staff Member'}</h5>
                    </div>
                    <span className={`badge px-3 py-2 rounded-pill ${view === 'available' ? 'bg-success-subtle text-success' : 'bg-primary-subtle text-primary'}`}>
                      {view === 'available' ? 'Available' : 'Booked'}
                    </span>
                  </div>

                  <div className="d-flex flex-column gap-3 mb-4 flex-grow-1">
                    <div className="d-flex align-items-center text-muted">
                      <ClockIcon />
                      <span>{formatDateTime(slot.date, slot.time)}</span>
                    </div>
                    <div className="d-flex align-items-center text-muted">
                      <HourglassIcon />
                      <span>{slot.duration} minutes</span>
                    </div>
                    <div className="d-flex align-items-center text-muted">
                      <BookIcon />
                      <span className="text-truncate" style={{ maxWidth: '200px' }}>
                        {slot.staffId?.subject || slot.topic || 'General Guidance'}
                      </span>
                    </div>
                  </div>

                  <div className="mt-auto pt-3 border-top border-secondary border-opacity-25">
                    {isSlotFinished(slot.date, slot.time, slot.duration) ? (
                      <button className="btn btn-secondary w-100 text-uppercase fw-bold rounded-3 py-2 opacity-50" disabled>
                        Done
                      </button>
                    ) : view === 'available' ? (
                      <button className="btn btn-premium w-100 rounded-3 py-2" onClick={() => handleBookSlot(slot._id)}>
                        Book Session
                      </button>
                    ) : (
                      <button className="btn btn-outline-danger w-100 rounded-3 py-2" onClick={() => handleCancelBooking(slot._id)}>
                        Cancel Booking
                      </button>
                    )}
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default SlotBookingPage;
